"use client";

import * as React from "react";
import {
  motion,
  type MotionValue,
  useMotionValueEvent,
  useTransform,
} from "motion/react";

import { cn } from "@/lib/utils";
import {
  clamp01,
  useHydrated,
  useMediaQuery,
  usePrefersReducedMotion,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type DepthGalleryItem = {
  className?: string;
  content: React.ReactNode;
  depth?: number;
  description?: string;
  eyebrow?: string;
  id: string;
  label?: string;
  title?: string;
};

export type DepthGalleryProps = Omit<React.ComponentProps<"section">, "children"> & {
  exitTravel?: number;
  itemClassName?: string;
  items: DepthGalleryItem[];
  label: string;
  onActiveChange?: (index: number, item: DepthGalleryItem) => void;
  scrollScreens?: number;
  stackOffset?: number;
  stageClassName?: string;
};

function FocusCard({
  active,
  index,
  item,
  itemClassName,
  itemCount,
  progress,
  exitTravel,
  stackOffset,
}: {
  active: boolean;
  exitTravel: number;
  index: number;
  item: DepthGalleryItem;
  itemClassName?: string;
  itemCount: number;
  progress: MotionValue<number>;
  stackOffset: number;
}) {
  const position = useTransform(progress, (value) => index - value * Math.max(itemCount - 1, 1));
  const depthStrength = Math.min(1, Math.abs(item.depth ?? 0.5));

  // Earlier cards always stay above later cards. They lift away to reveal the
  // next frame below, so no z-index handoff can flicker mid-transition.
  const y = useTransform(position, (value) => {
    if (value < 0) return `${Math.max(-exitTravel, value * exitTravel)}%`;
    return `${Math.min(2, value) * stackOffset}%`;
  });
  const z = useTransform(position, (value) => {
    if (value < 0) return Math.min(1, -value) * 24;
    return -Math.min(2, value) * (86 + depthStrength * 54);
  });
  const scale = useTransform(position, (value) => {
    if (value < 0) return 1 + Math.min(1, -value) * 0.025;
    return 1 - Math.min(2, value) * (0.052 + depthStrength * 0.01);
  });
  const opacity = useTransform(position, (value) => {
    if (value < -0.82) return clamp01(1 - (-value - 0.82) / 0.18);
    if (value > 2) return clamp01(1 - (value - 2) * 4);
    return 1;
  });
  const contentOpacity = useTransform(position, (value) => {
    if (value < 0) return clamp01(1 - -value / 0.34);
    return clamp01(1 - value / 0.24);
  });
  const rotateX = useTransform(position, (value) => {
    if (value < 0) return Math.max(-2.5, value * 2.5);
    return Math.min(2.5, value * 1.5);
  });

  return (
    <motion.article
      role="listitem"
      aria-current={active ? "true" : undefined}
      aria-hidden={!active}
      aria-label={item.label ?? item.title}
      data-depth-gallery-item={item.id}
      inert={!active}
      className={cn(
        "absolute left-1/2 top-1/2 aspect-[16/10] w-[min(88vw,68rem)] -translate-x-1/2 -translate-y-1/2 overflow-hidden rounded-[clamp(1.25rem,3vw,2.5rem)] bg-muted shadow-2xl [backface-visibility:hidden] will-change-transform",
        itemClassName,
        item.className,
      )}
      style={{ opacity, pointerEvents: active ? "auto" : "none", rotateX, scale, transformStyle: "preserve-3d", y, z, zIndex: itemCount - index }}
    >
      <div className="absolute inset-0">{item.content}</div>
      {item.eyebrow || item.title || item.description ? (
        <motion.div className="pointer-events-none absolute inset-0 flex items-end bg-gradient-to-t from-black/80 via-black/10 to-transparent p-[clamp(1.5rem,4vw,4rem)] text-white" style={{ opacity: contentOpacity }}>
          <div className="max-w-2xl">
            {item.eyebrow ? <p className="text-xs font-semibold uppercase tracking-[0.2em] text-white/65">{item.eyebrow}</p> : null}
            {item.title ? <h3 className="mt-3 text-[clamp(2.2rem,6vw,6rem)] font-semibold leading-[0.9] tracking-[-0.06em]">{item.title}</h3> : null}
            {item.description ? <p className="mt-4 max-w-lg text-sm leading-relaxed text-white/70 sm:text-base">{item.description}</p> : null}
          </div>
        </motion.div>
      ) : null}
    </motion.article>
  );
}

/**
 * A clear, scroll-driven focus stack: the next frame approaches the camera,
 * the current frame locks into focus, and the previous frame recedes.
 */
export function DepthGallery({
  className,
  exitTravel = 112,
  itemClassName,
  items,
  label,
  onActiveChange,
  scrollScreens,
  stackOffset = 7,
  stageClassName,
  style,
  ...props
}: DepthGalleryProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const reducedMotion = usePrefersReducedMotion();
  const hydrated = useHydrated();
  const coarseOrNarrow = useMediaQuery("(pointer: coarse), (max-width: 767.98px)");
  // SSR tradeoff: the server cannot know pointer/viewport, so mobile's first paint is the 3D stack; gating on hydration makes the carousel swap land exactly once, post-mount.
  const compact = hydrated && coarseOrNarrow;
  const staticLayout = reducedMotion || compact;
  const [activeIndex, setActiveIndex] = React.useState(0);
  const scrollYProgress = useElementScrollProgress(rootRef);

  useMotionValueEvent(scrollYProgress, "change", (value) => {
    if (items.length === 0) return;
    const position = value * Math.max(items.length - 1, 1);
    const nextIndex = Math.max(0, Math.min(items.length - 1, Math.floor(position + 0.2)));
    setActiveIndex((current) => {
      if (current === nextIndex) return current;
      onActiveChange?.(nextIndex, items[nextIndex]!);
      return nextIndex;
    });
  });

  if (items.length === 0) return null;

  if (staticLayout) {
    return (
      <section ref={rootRef} aria-label={label} data-depth-gallery data-static className={cn("relative min-h-svh", className)} style={style} {...props}>
        <div role="list" className="flex min-h-svh snap-x snap-mandatory items-center gap-4 overflow-x-auto px-5 py-24 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
          {items.map((item) => (
            <article key={item.id} role="listitem" aria-label={item.label ?? item.title} className={cn("relative aspect-[4/5] min-w-[84vw] snap-center overflow-hidden rounded-[1.5rem] bg-muted sm:min-w-[52vw]", itemClassName, item.className)}>
              <div className="absolute inset-0">{item.content}</div>
              <div className="absolute inset-0 flex items-end bg-gradient-to-t from-black/80 via-transparent to-transparent p-6 text-white">
                <div>{item.eyebrow ? <p className="text-xs uppercase tracking-[0.2em] text-white/60">{item.eyebrow}</p> : null}{item.title ? <h3 className="mt-2 text-4xl font-semibold tracking-[-0.05em]">{item.title}</h3> : null}{item.description ? <p className="mt-3 text-sm text-white/70">{item.description}</p> : null}</div>
              </div>
            </article>
          ))}
        </div>
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-active-index={activeIndex}
      data-depth-gallery
      className={cn("relative isolate", className)}
      style={{ minHeight: `${Math.max(items.length, scrollScreens ?? items.length) * 100}svh`, perspective: 1200, ...style }}
      {...props}
    >
      <div className={cn("sticky top-0 h-svh overflow-hidden [transform-style:preserve-3d]", stageClassName)}>
        <div role="list" className="absolute inset-0 [transform-style:preserve-3d]">
          {items.map((item, index) => (
            <FocusCard
              key={item.id}
              active={index === activeIndex}
              exitTravel={exitTravel}
              index={index}
              item={item}
              itemClassName={itemClassName}
              itemCount={items.length}
              progress={scrollYProgress}
              stackOffset={stackOffset}
            />
          ))}
        </div>
        <div aria-hidden className="absolute bottom-6 right-6 z-30 flex gap-2">
          {items.map((item, index) => <span key={item.id} className={cn("h-1 rounded-full bg-white/45 transition-[width,background-color]", index === activeIndex ? "w-10 bg-white" : "w-3")} />)}
        </div>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const travel = Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}

# Focus Depth Gallery

Secvență focală fără WebGL: cadrul curent se ridică și descoperă următorul cadru aflat dedesubt. Ordinea stivei rămâne fixă pe toată tranziția, astfel încât nu există schimbări de `z-index`, intercalări de text sau blur animat.

## Instalare și exemplu

```bash
npx shadcn@latest add ./public/r/depth-gallery.json
```

```tsx
<DepthGallery
  label="Selecție de proiecte"
  stackOffset={7}
  exitTravel={112}
  items={projects.map((project) => ({
    id: project.id,
    label: project.title,
    eyebrow: project.category,
    title: project.title,
    description: project.summary,
    content: <ProjectImage project={project} />,
  }))}
/>
```

Pe desktop stage-ul rămâne sticky, iar scroll-ul vertical ridică cadrul activ și aduce următorul cadru de dedesubt. Caption-ul vechi dispare devreme, iar cel nou apare abia după ce takeover-ul este aproape complet. `stackOffset` controlează cât din cadrele următoare se vede în stivă, iar `exitTravel` cât de departe pleacă cadrul curent. Scroll-ul înapoi inversează natural aceeași tranziție.

Pe pointer coarse, mobil sau reduced motion, componenta devine un rail cu swipe și snap. Item-urile rămân conținut React normal.

## Personalizare obligatorie pentru AI

- construiește o succesiune cu motiv clar și 3–6 cadre distincte; `depth` ajustează distanța de recul, nu definește un grid aleator;
- personalizează crop-uri, overlay, metadata, spațiere și starea mobilă;
- nu schimba ordinea stivei în timpul tranziției și nu anima blur-ul; cadrul anterior trebuie să descopere fizic următorul cadru;
- verifică tab order, swipe, overflow, imagini portrait/landscape și resize;
- respinge dacă toate item-urile au aceeași adâncime, transformările taie conținutul sau o grilă statică ar fi mai clară.

Recomandat 3–7 item-uri vizibile și imagini responsive; evită blur-urile animate.

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
